111	// Parity-based wait for the direct-write consumers. mbarriers initialised
112	// with ``arrive_count == 1`` and signalled exclusively by the producer's
113	// ``cuda::device::barrier_arrive_tx`` (inside ``load_2d``) flip phase as
114	// soon as the TMA's tx-count is satisfied. Consumers must therefore wait
115	// on the *current* phase bit (0 on the first reuse, 1 on the second,
116	// alternating thereafter) instead of using ``wait(arrive())`` -- the
117	// latter would over-arrive and corrupt the next phase.
118	__device__ __forceinline__ void wait_barrier_parity(barrier_t& barrier,
119	                                                    uint32_t phase) {
120	  barrier.wait_parity(phase != 0);
121	  // The TMA bulk-tensor copy writes via the async proxy; ldmatrix.sync (used
122	  // by the consumer) reads via the generic proxy. mbarrier wait_parity
123	  // alone provides only completion of the TMA, not cross-proxy visibility
124	  // for sm_120 / Blackwell, where a generic-proxy reader must observe an
125	  // explicit ``fence.proxy.async.shared::cta`` after the producer arrival.
126	  cde::fence_proxy_async_shared_cta();
127	}
