206	    T* dst_smem_base_ptr, const CUtensorMap* tensor_map, const int major_coord,
207	    const int d_tile_id, const int dst_stage, barrier_t& barrier,
208	    int issuer_lane = 0) {
209	  if (tensor_map == nullptr || d_tile_id >= (kHeadDim / kCols)) {
210	    return false;
211	  }
212	  T* dst_stage_ptr = dst_smem_base_ptr + dst_stage * kTileSize;
213	  load_2d(dst_stage_ptr, tensor_map, d_tile_id * kCols, major_coord, barrier,
214	          BrOrBc * kCols * sizeof(T), issuer_lane);
215	  return true;
216	}
