218	// Legacy scratch+repack issuer: issue an asynchronous TMA load of one
219	// (BrOrBc, kCols) tile into the caller-owned scratch slot ``tmp_stage``
220	// of ``tmp_smem_base_ptr``. Kept for the scratch+repack flow; new code
221	// on SM90+ should prefer ``issue_load_2d_to_dst_swizzled`` above.
222	template <const int BrOrBc, const int kHeadDim, const int kCols, typename T>
223	__device__ __forceinline__ bool issue_load_2d_to_tmp(
224	    T* tmp_smem_base_ptr, const CUtensorMap* tensor_map, const int major_coord,
225	    const int d_tile_id, const int tmp_stage, const int seqlen_bound,
226	    barrier_t& barrier) {
227	  if (tensor_map == nullptr || d_tile_id >= (kHeadDim / kCols) ||
228	      ((major_coord + BrOrBc) > seqlen_bound)) {
229	    return false;
230	  }
231	  T* tmp_stage_ptr = tmp_smem_base_ptr + tmp_stage * BrOrBc * kCols;
232	  load_2d(tmp_stage_ptr, tensor_map, d_tile_id * kCols, major_coord, barrier,
233	          BrOrBc * kCols * sizeof(T));
234	  return true;
235	}
236	
237	// Wait on ``barrier`` (signalled by the matching ``issue_load_2d_to_tmp``
238	// call with the same ``tmp_stage``) and repack the contiguous TMA scratch
239	// tile at ``tmp_smem_base_ptr[tmp_stage]`` into the kernel's existing
240	// padded (kPad>0) or XOR-swizzled (kPad==0) destination slot
241	// ``dst_smem_base_ptr[dst_stage]``. All threads in the block participate.
242	//
243	// MUST only be invoked when the matching ``issue_load_2d_to_tmp`` returned
244	// ``true``; otherwise the wait will block forever (no producer arrival).
245	template <const int BrOrBc, const int kTileSize, const int kCols,
246	          const int kNumThreads, const int kPad, typename T>
247	__device__ __forceinline__ void wait_and_repack_tmp_to_dst(T* dst_smem_base_ptr,
248	                                                           T* tmp_smem_base_ptr,
249	                                                           const int dst_stage,
250	                                                           const int tmp_stage,
251	                                                           barrier_t& barrier) {
252	  constexpr bool kSwizzle = (kPad == 0);
253	  constexpr int kElemsPerThread = kCols / (kNumThreads / BrOrBc);
254	  static_assert(kElemsPerThread * sizeof(T) == 16,
255	                "Experimental TMA repack expects one 16B vector per thread.");
256	
257	  T* tmp_stage_ptr = tmp_smem_base_ptr + tmp_stage * BrOrBc * kCols;
258	  wait_barrier(barrier);
259	  __syncthreads();
260	
261	  const int tid = threadIdx.x;
262	  const int row = tid / (kNumThreads / BrOrBc);
263	  const int col = (tid % (kNumThreads / BrOrBc)) * kElemsPerThread;
264	  T* src = tmp_stage_ptr + row * kCols + col;
265	  T* dst = dst_smem_base_ptr + dst_stage * kTileSize + row * (kCols + kPad) +
266	           (kSwizzle ? (((col >> 3) ^ (row >> 2)) % (kCols >> 3)) << 3 : col);
267	  *reinterpret_cast<uint4*>(dst) = *reinterpret_cast<uint4*>(src);
268	  __syncthreads();
269	}
270	
271	// Legacy synchronous helper kept for completeness: issues, waits and
272	// repacks in a single call. Equivalent to ``issue_load_2d_to_tmp`` +
273	// ``wait_and_repack_tmp_to_dst`` back-to-back. New code should prefer
274	// the split helpers so that the issue and the wait can be hoisted apart
275	// to enable multi-stage TMA pipelining.
276	template <const int BrOrBc, const int kTileSize, const int kHeadDim,
277	          const int kCols, const int kNumThreads, const int kPad, typename T>
278	__device__ __forceinline__ bool load_2d_to_smem_repack(
279	    T* dst_smem_base_ptr, T* tmp_smem_base_ptr, const CUtensorMap* tensor_map,
280	    const int major_coord, const int d_tile_id, const int dst_stage,
281	    const int tmp_stage, const int seqlen_bound, barrier_t& barrier) {
282	  if (!issue_load_2d_to_tmp<BrOrBc, kHeadDim, kCols, T>(
283	          tmp_smem_base_ptr, tensor_map, major_coord, d_tile_id, tmp_stage,
284	          seqlen_bound, barrier)) {
285	    return false;
286	  }
287	  wait_and_repack_tmp_to_dst<BrOrBc, kTileSize, kCols, kNumThreads, kPad, T>(
288	      dst_smem_base_ptr, tmp_smem_base_ptr, dst_stage, tmp_stage, barrier);
289	  return true;
290	}
291	#else
292	__device__ __forceinline__ void init_barrier(barrier_t* barrier,
293	                                             int arrive_count) {
294	  (void)barrier;
295	  (void)arrive_count;
296	}
297	
298	__device__ __forceinline__ void wait_barrier(barrier_t& barrier) {
299	  (void)barrier;
300	}
301	
302	__device__ __forceinline__ void wait_barrier_parity(barrier_t& barrier,
303	                                                    uint32_t phase) {
304	  (void)barrier;
305	  (void)phase;
306	}
307	
308	__device__ __forceinline__ void bulk_commit_group() {}
309	
310	template <size_t n>
311	__device__ __forceinline__ void bulk_wait_group() {}
312	
313	__device__ __forceinline__ void load_2d(void* smem_ptr,
314	                                        const CUtensorMap* tensor_map,
315	                                        int32_t minor_coord,
316	                                        int32_t major_coord, barrier_t& barrier,
317	                                        uint32_t bytes, int issuer_lane = 0) {
318	  (void)smem_ptr;
319	  (void)tensor_map;
320	  (void)minor_coord;
321	  (void)major_coord;
322	  (void)barrier;
323	  (void)bytes;
324	  (void)issuer_lane;
325	}
326	
327	template <const int BrOrBc, const int kHeadDim, const int kCols,
328	          const int kTileSize, typename T>
329	__device__ __forceinline__ bool issue_load_2d_to_dst_swizzled(
330	    T* dst_smem_base_ptr, const CUtensorMap* tensor_map, const int major_coord,
331	    const int d_tile_id, const int dst_stage, barrier_t& barrier,
332	    int issuer_lane = 0) {
333	  (void)dst_smem_base_ptr;
334	  (void)tensor_map;
335	  (void)major_coord;
336	  (void)d_tile_id;
337	  (void)dst_stage;
338	  (void)barrier;
339	  (void)issuer_lane;
340	  return false;
341	}
342	
343	template <const int BrOrBc, const int kHeadDim, const int kCols, typename T>
